102	async function pullOperatorContext(userMessage: string): Promise<string> {
103	  const dbUrl = process.env.DATABASE_URL;
104	  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';
105	
106	  const db = neon(dbUrl);
107	  const sections: string[] = [];
108	
109	  const anchor = await pullIdentityAnchor(db);
110	  if (anchor) sections.push(anchor);
111	  sections.push(YETTRAGRAMMATON);
112	
113	  const recent = await db`
114	    SELECT LEFT(content, 2500) AS content, created_at
115	    FROM omega_memory_entries
116	    ORDER BY created_at DESC
117	    LIMIT 20
118	  `.catch(() => [] as Row[]);
119	
120	  if ((recent as Row[]).length > 0) {
121	    sections.push('=== RECENT MEMORY ENTRIES ===');
122	    for (const r of recent as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
123	  }
124	
125	  const keywords = userMessage
126	    .toLowerCase()
127	    .replace(/[^a-z0-9 ]/g, ' ')
128	    .split(/\s+/)
129	    .filter(w => w.length > 3)
130	    .slice(0, 3);
131	
132	  if (keywords.length > 0) {
133	    const pattern = `%${keywords[0]}%`;
134	    const relevant = await db`
135	      SELECT LEFT(content, 2000) AS content, created_at
136	      FROM omega_memory_entries
137	      WHERE content ILIKE ${pattern}
138	      ORDER BY created_at DESC
139	      LIMIT 10
140	    `.catch(() => [] as Row[]);
141	
142	    if ((relevant as Row[]).length > 0) {
143	      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
144	      for (const r of relevant as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
145	    }
146	  }
147	
148	  const marginalia = await db`SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
149	  if ((marginalia as Row[]).length > 0) {
150	    sections.push('\n=== MARGINALIA ===');
151	    for (const m of marginalia as Row[]) sections.push(JSON.stringify(m));
152	  }
153	
154	  const events = await db`SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
155	  if ((events as Row[]).length > 0) {
156	    sections.push('\n=== SYSTEM EVENTS ===');
157	    for (const e of events as Row[]) sections.push(JSON.stringify(e));
