export async function POST(req: NextRequest) {
  try {
    const { user, history, sessionId, voiceMode } = (await req.json()) as { user: string; history?: Msg[]; sessionId?: string; voiceMode?: boolean };

    if (!user?.trim()) {
      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
    }

    const interactionMode = resolveInteractionMode(req);
    const interactionPolicy = getInteractionPolicy(interactionMode);

    const dbUrl = process.env.DATABASE_URL;
    const db = dbUrl ? neon(dbUrl) : null;
    let finalSessionId = sessionId;

    if (db && !finalSessionId) {
      try {
        const res = await db`INSERT INTO omega_sessions DEFAULT VALUES RETURNING id`;
        if (res?.length > 0) finalSessionId = res[0].id as string;
      } catch (e) {
        console.error('[OmegA] Session creation failed', e);
      }
    }

    const encoder = new TextEncoder();
    const decoder = new TextDecoder();

    const sessionHistory = db && finalSessionId
      ? await loadSessionHistory(db, finalSessionId)
      : (history ?? []);
    const phylactery = await hydratePhylactery(sessionHistory);
    const omega = new OmegaStack();
    const preflight = omega.preflight(user, phylactery.head);

    if (db && finalSessionId) {
      try {
        await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`;
      } catch (e) {
        console.error('[OmegA] DB write error', e);
      }
    }

    if (!preflight.allowed) {
      const blocked = preflight.blockedResponse ?? '[BLOCKED] Request denied by AEGIS governance.';
      if (db && finalSessionId) {
        try {
          await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${blocked})`;
        } catch (e) {
          console.error('[OmegA] DB save error', e);
        }
      }

      return new NextResponse(blocked, {
        headers: {
          'Content-Type': 'text/plain; charset=utf-8',
          'X-Session-Id': finalSessionId || '',
          'X-Memory-Backend': db ? 'neon-live' : 'none',
          'X-Omega-Stack': 'aegis-aeon-adccl-myelin',
          'X-Omega-Outcome': 'blocked',
          'X-Omega-Mode': interactionPolicy.mode,
          'X-Omega-Corpus-Class': interactionPolicy.corpusClass,
          'X-Omega-Envelope-Version': String(preflight.envelopeVersion),
          'X-Omega-Phylactery-Head': phylactery.head,
          'X-Omega-Risk-Score': preflight.risk.score.toFixed(4),
        }
      });
    }

    let contextBlock: string;
    try {
      contextBlock = await buildContextForPolicy(interactionPolicy, user, () => pullOperatorContext(user));
    } catch (e) {
      console.warn('[OmegA] DB pull failed:', e);
      contextBlock = interactionPolicy.mode === 'operator'
        ? '(Memory bank unreachable — reasoning independently)'
        : '(Curated public corpus unavailable — answer only from the request and stable public-facing knowledge already established in this runtime.)';
    }

    const conversationContext = sessionHistory.length
      ? `\n━━━ SESSION CONVERSATION HISTORY ━━━\n\n` +
        sessionHistory.map(m => `[${m.role === 'omega' ? 'OmegA' : 'User'}]: ${m.text}`).join('\n\n') +
        `\n\n━━━ END HISTORY ━━━\n`
      : '';

    const voiceDirective = voiceMode ? `\n\n━━━ VOICE MODE ━━━\nYou are speaking aloud. The user will hear your response via text-to-speech.\nRules:\n- Keep responses under 3 sentences unless a longer answer is truly necessary.\n- No markdown formatting, no bullet points, no headers — plain spoken sentences only.\n- No "certainly", "of course", "absolutely". Just answer directly.\n- If you need to think through something complex, say one sentence summary then offer to go deeper.\n━━━ END VOICE MODE ━━━` : '';
    const omegaDirective = omega.buildIdentityDirective(phylactery.head);
    const modeDirective = `${interactionPolicy.interactionDirective}\n${interactionPolicy.boundaryDirective}`;
    const synthesisDirective = interactionPolicy.mode === 'operator' ? SYNTHESIS_DIRECTIVE : PUBLIC_SYNTHESIS_DIRECTIVE;
    const contextLabel = interactionPolicy.mode === 'operator' ? 'RAW DATA FROM MEMORY SYSTEMS' : 'PUBLIC KNOWLEDGE CONTEXT';
    const system = `${omegaDirective}\n\n${modeDirective}\n\n${synthesisDirective}\n\n${ANTI_ECHO_DIRECTIVE}\n\n━━━ ${contextLabel} ━━━\n\n${contextBlock}\n\n━━━ END ${contextLabel} ━━━\n${conversationContext}${voiceDirective}`;

    const providerHealth = getProviderHealthSnapshot();
    const providerFns: Record<ProviderName, () => Promise<ReadableStream>> = {
      'vercel-gateway': () => tryVercelGateway(encoder, system, user, sessionHistory),
      'openai-direct': () => tryOpenAIDirect(encoder, system, user, sessionHistory),
      'xai-direct': () => tryXaiDirect(encoder, system, user, sessionHistory),
      '-flash': () => try(encoder, system, user, sessionHistory),
    };

    const providers = getProviderOrder().map(name => ({ name, fn: providerFns[name] }));
    const selection = await selectStreamingProvider(providers, encoder, decoder);
    const { provider, stream: providerStream, attempts: providerAttempts } = selection;

    const customStream = new ReadableStream({
      async start(controller) {
        try {
          controller.enqueue(encoder.encode('data: {"type":"status","text":"reading memory..."}\n\n'));
          controller.enqueue(encoder.encode('data: {"type":"status","text":"synthesizing..."}\n\n'));

          const reader = providerStream.getReader();
          let fullResponse = '';
          const isPublicMode = interactionPolicy.mode === 'public';
          while (true) {
            const { value, done } = await reader.read();
            if (done) break;
            const raw = decoder.decode(value, { stream: true });
            if (raw) {
              const text = isPublicMode ? scrubPrivateData(raw) : raw;
              fullResponse += text;
              controller.enqueue(encoder.encode(text));
            }
          }

          const postflight = await omega.postflight(user, fullResponse, phylactery, preflight.envelopeVersion);

          if (db && finalSessionId && fullResponse) {
            try {
              await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`;
            } catch (e) {
              console.error('[OmegA] DB save error', e);
            }
          }

          console.info('[OmegA] Postflight', {
            sessionId: finalSessionId,
            envelopeVersion: postflight.envelopeVersion,
            outcome: postflight.selfTag.outcome,
            verification: postflight.verification.V,
            phylacteryHead: postflight.phylacteryHead,
          });

          controller.close();
        } catch (err) {
          console.error('[OmegA] Stream error', err);
          controller.error(err);
        }
      }
    });

    return new NextResponse(customStream, {
      headers: {
        'Content-Type': 'text/plain; charset=utf-8',
        'X-Session-Id': finalSessionId || '',
        'X-Provider': provider,
        'X-Memory-Backend': db ? 'neon-live' : 'none',
        'X-Provider-Health': JSON.stringify(providerHealth),
        'X-Omega-Stack': 'aegis-aeon-adccl-myelin',
        'X-Omega-Outcome': 'allowed',
        'X-Omega-Mode': interactionPolicy.mode,
        'X-Omega-Corpus-Class': interactionPolicy.corpusClass,
        'X-Omega-Envelope-Version': String(preflight.envelopeVersion),
        'X-Omega-Phylactery-Head': phylactery.head,
        'X-Omega-Risk-Score': preflight.risk.score.toFixed(4),
        'X-Provider-Attempts': providerAttempts
          .map(p => (p.status === 'failed' ? `${p.name}:failed` : `${p.name}:selected`))
          .join(' -> '),
      }
    });

  } catch (err) {
    console.error('[OmegA] POST error', err);
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

