'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import s from './dashboard.module.css';

interface Signal {
  id: number;
  category: string;
  source: string;
  metric_name: string;
  metric_value: number;
  unit: string | null;
  confidence_score: number;
  raw_source_url: string | null;
  timestamp: string;
}

interface RuntimeStatus {
  app: string;
  sovereignStack: string;
  posture: {
    activeMode: 'operator' | 'public';
    publicCorpus: {
      corpusClass: string;
      entryCount: number;
      categories: string[];
      entryIds: string[];
    };
    operatorConfigured: boolean;
  };
  deployment: {
    nodeEnv: string;
    vercelEnv: string;
    commitSha: string | null;
    region: string | null;
    deploymentUrl: string | null;
  };
  services: {
    databaseConfigured: boolean;
    gatewayConfigured: boolean;
    openaiConfigured: boolean;
    xaiConfigured: boolean;
    Configured: boolean;
    livekitConfigured: boolean;
  };
  providerOrder: string[];
  providerHealth: {
    gateway: { configured: boolean; available: boolean; reason: string | null; authSource: string | null };
    openai: { configured: boolean; available: boolean; reason: string | null };
    xai: { configured: boolean; available: boolean; reason: string | null };
    : { configured: boolean; available: boolean; reason: string | null; keysConfigured: number };
  };
}

const CATEGORY_LABELS: Record<string, string> = {
  uranium: 'U',
  nuclear: 'N',
  compute: 'C',
};

const CATEGORY_COLORS: Record<string, string> = {
  uranium: '#00ff80',
  nuclear: '#22d3ee',
  compute: '#c4b5fd',
};

export default function Dashboard() {
  const [signals, setSignals] = useState<Signal[]>([]);
  const [runtime, setRuntime] = useState<RuntimeStatus | null>(null);
  const [operatorToken, setOperatorToken] = useState('');
  const [operatorStatus, setOperatorStatus] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = useState<Date | null>(null);

  const fetchSignals = useCallback(async () => {
    try {
      const [signalsRes, runtimeRes] = await Promise.all([
        fetch('/api/signals'),
        fetch('/api/runtime-status'),
      ]);

      if (!signalsRes.ok) throw new Error(`${signalsRes.status}`);
      if (!runtimeRes.ok) throw new Error(`runtime ${runtimeRes.status}`);

      const data = await signalsRes.json();
      const runtimeData = await runtimeRes.json();

      if (Array.isArray(data)) {
        setSignals(data);
      }
      setRuntime(runtimeData);
      setError(null);
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
      setLastRefresh(new Date());
    }
  }, []);

  useEffect(() => { fetchSignals(); }, [fetchSignals]);

  // Auto-refresh every 30s
  useEffect(() => {
    const interval = setInterval(fetchSignals, 30000);
    return () => clearInterval(interval);
  }, [fetchSignals]);

  const unlockOperatorMode = useCallback(async () => {
    setOperatorStatus(null);
    try {
      const res = await fetch('/api/operator/session', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: operatorToken }),
      });

      if (!res.ok) {
        const body = await res.json().catch(() => ({ error: 'Unlock failed' }));
        throw new Error(body.error ?? 'Unlock failed');
      }

      setOperatorToken('');
      setOperatorStatus('operator mode unlocked');
      await fetchSignals();
    } catch (err) {
      setOperatorStatus(err instanceof Error ? err.message : 'Unlock failed');
    }
  }, [fetchSignals, operatorToken]);

  const lockOperatorMode = useCallback(async () => {
    setOperatorStatus(null);
    try {
      const res = await fetch('/api/operator/session', { method: 'DELETE' });
      if (!res.ok) throw new Error('Lock failed');
      setOperatorStatus('returned to public mode');
      await fetchSignals();
    } catch (err) {
      setOperatorStatus(err instanceof Error ? err.message : 'Lock failed');
    }
  }, [fetchSignals]);

  const grouped = signals.reduce<Record<string, Signal[]>>((acc, sig) => {
    (acc[sig.category] = acc[sig.category] || []).push(sig);
    return acc;
  }, {});

  return (
    <div className={s.root}>
      {/* Header */}
      <header className={s.header}>
        <div className={s.headerLeft}>
          <span className={s.glyph}>&Omega;</span>
          <span className={s.title}>SID</span>
          <span className={s.subtitle}>Sovereign Intelligence Dashboard</span>
        </div>
        <div className={s.headerRight}>
          <span className={s.dot} />
          <span className={s.statusText}>
            {loading ? 'Syncing...' : error ? 'Link Error' : 'Live'}
          </span>
          {lastRefresh && (
            <span className={s.refreshTime}>
              {lastRefresh.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </span>
          )}
          <button className={s.refreshBtn} onClick={fetchSignals} title="Refresh now">
            &#8635;
          </button>
        </div>
      </header>

      <div className={s.borderLine} />

      {/* Content */}
      <main className={s.main}>
        {runtime && (
          <section className={s.runtimeSection}>
            <div className={s.runtimeSectionHeader}>
              <span className={s.runtimeTitle}>Runtime Status</span>
              <span className={s.runtimeStack}>{runtime.sovereignStack}</span>
            </div>
            <div className={s.runtimeGrid}>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Interaction Mode</div>
                <div className={s.runtimeCardValue}>{runtime.posture.activeMode}</div>
                <div className={s.runtimeCardSub}>{runtime.posture.publicCorpus.corpusClass}</div>
              </div>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Deployment</div>
                <div className={s.runtimeCardValue}>{runtime.deployment.vercelEnv}</div>
                <div className={s.runtimeCardSub}>Node {runtime.deployment.nodeEnv}</div>
              </div>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Commit</div>
                <div className={s.runtimeCardValue}>{runtime.deployment.commitSha?.slice(0, 7) ?? 'local'}</div>
                <div className={s.runtimeCardSub}>{runtime.deployment.region ?? 'region n/a'}</div>
              </div>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Provider Order</div>
                <div className={s.runtimeCardValue}>{runtime.providerOrder.join(' -> ')}</div>
                <div className={s.runtimeCardSub}>routing preference</div>
              </div>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Memory / Services</div>
                <div className={s.runtimeCardValue}>
                  {runtime.services.databaseConfigured ? 'db on' : 'db off'} / {runtime.services.gatewayConfigured ? 'gateway on' : 'gateway off'}
                </div>
                <div className={s.runtimeCardSub}>
                  {runtime.services.xaiConfigured ? 'xai' : '-'} {runtime.services.Configured ? '' : '-'} {runtime.services.openaiConfigured ? 'openai' : '-'} {runtime.services.livekitConfigured ? 'livekit' : '-'}
                </div>
              </div>
              <div className={s.runtimeCard}>
                <div className={s.runtimeCardLabel}>Public Corpus</div>
                <div className={s.runtimeCardValue}>{runtime.posture.publicCorpus.entryCount} entries</div>
                <div className={s.runtimeCardSub}>{runtime.posture.publicCorpus.categories.join(' · ')}</div>
              </div>
            </div>
            <div className={s.operatorPanel}>
              <div className={s.operatorPanelHeader}>
                <span className={s.operatorTitle}>Operator Access</span>
                <span className={runtime.posture.operatorConfigured ? s.operatorReady : s.operatorUnset}>
                  {runtime.posture.operatorConfigured ? 'configured' : 'not configured'}
                </span>
              </div>
              <div className={s.operatorControls}>
                <input
                  className={s.operatorInput}
                  type="password"
                  value={operatorToken}
                  onChange={(event) => setOperatorToken(event.target.value)}
                  placeholder="Enter operator token"
                />
                <button className={s.operatorButton} onClick={unlockOperatorMode} disabled={!operatorToken.trim()}>
                  Unlock
                </button>
                <button className={s.operatorButtonMuted} onClick={lockOperatorMode}>
                  Return Public
                </button>
              </div>
              {operatorStatus && <div className={s.operatorStatus}>{operatorStatus}</div>}
            </div>
            <div className={s.providerGrid}>
              <div className={s.providerRow}>
                <span className={s.providerName}>Gateway</span>
                <span className={runtime.providerHealth.gateway.available ? s.providerOk : s.providerWarn}>
                  {runtime.providerHealth.gateway.available ? 'available' : runtime.providerHealth.gateway.reason ?? 'offline'}
                </span>
              </div>
              <div className={s.providerRow}>
                <span className={s.providerName}>xAI</span>
                <span className={runtime.providerHealth.xai.available ? s.providerOk : s.providerWarn}>
                  {runtime.providerHealth.xai.available ? 'available' : runtime.providerHealth.xai.reason ?? 'offline'}
                </span>
              </div>
              <div className={s.providerRow}>
                <span className={s.providerName}></span>
                <span className={runtime.providerHealth..available ? s.providerOk : s.providerWarn}>
                  {runtime.providerHealth..available ? `available (${runtime.providerHealth..keysConfigured} keys)` : runtime.providerHealth..reason ?? 'offline'}
                </span>
              </div>
              <div className={s.providerRow}>
                <span className={s.providerName}>OpenAI</span>
                <span className={runtime.providerHealth.openai.available ? s.providerOk : s.providerWarn}>
                  {runtime.providerHealth.openai.available ? 'available' : runtime.providerHealth.openai.reason ?? 'offline'}
                </span>
              </div>
            </div>
          </section>
        )}

        {loading && signals.length === 0 && (
          <div className={s.empty}>Scanning signal stack...</div>
        )}

        {error && (
          <div className={s.errorBar}>{error}</div>
        )}

        {!loading && signals.length === 0 && !error && (
          <div className={s.empty}>
            <div className={s.emptyGlyph}>&Omega;</div>
            <div>No signals ingested yet.</div>
            <div className={s.emptyHint}>POST to /api/signals to populate the dashboard.</div>
          </div>
        )}

        {Object.entries(grouped).map(([category, sigs]) => (
          <section key={category} className={s.section}>
            <div className={s.sectionHeader}>
              <span
                className={s.categoryBadge}
                style={{ borderColor: CATEGORY_COLORS[category] || '#666', color: CATEGORY_COLORS[category] || '#666' }}
              >
                {CATEGORY_LABELS[category] || category.charAt(0).toUpperCase()}
              </span>
              <span className={s.categoryLabel}>{category}</span>
              <span className={s.signalCount}>{sigs.length}</span>
            </div>

            <div className={s.grid}>
              {sigs.map((sig) => (
                <div key={sig.id} className={s.card}>
                  <div className={s.cardTop}>
                    <span className={s.metricName}>{sig.metric_name}</span>
                    <span className={s.source}>{sig.source}</span>
                  </div>
                  <div className={s.metricRow}>
                    <span
                      className={s.metricValue}
                      style={{ color: CATEGORY_COLORS[sig.category] || '#fff' }}
                    >
                      {typeof sig.metric_value === 'number'
                        ? sig.metric_value.toLocaleString(undefined, { maximumFractionDigits: 4 })
                        : sig.metric_value}
                    </span>
                    {sig.unit && <span className={s.unit}>{sig.unit}</span>}
                  </div>
                  <div className={s.cardBottom}>
                    <span className={s.timestamp}>
                      {new Date(sig.timestamp).toLocaleString([], {
                        month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit',
                      })}
                    </span>
                    {sig.confidence_score < 1 && (
                      <span className={s.confidence}>
                        {Math.round(sig.confidence_score * 100)}%
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        ))}
      </main>

      {/* Nav back to OmegA */}
      <nav className={s.nav}>
        <Link href="/" className={s.navLink}>&larr; OmegA Chat</Link>
        <Link href="/omega.html" className={s.navLink}>Voice Interface &rarr;</Link>
      </nav>
    </div>
  );
}

