1	// Chat now routes through /api/chat (server-side) which pulls raw DB context
2	// before calling the gateway. No static biography — OmegA synthesizes from data.
3	
4	export interface ChatRequest {
5	  user: string;
6	  history?: { role: "user" | "omega"; text: string; timestamp?: string }[];
7	  sessionId?: string;
8	  voiceMode?: boolean;
9	}
10	
11	export interface ChatResponse {
12	  reply?: string;
13	  response?: string;
14	  provider?: string;
15	  sessionId?: string;
16	}
17	
18	export interface OmegaRuntimeMetadata {
19	  omegaStack?: string;
20	  omegaOutcome?: string;
21	  omegaMode?: string;
22	  omegaCorpusClass?: string;
23	  omegaEnvelopeVersion?: string;
24	  omegaPhylacteryHead?: string;
25	  omegaRiskScore?: string;
26	  provider?: string;
27	  providerAttempts?: string;
28	  sessionId?: string;
29	  memoryBackend?: string;
30	}
31	
32	export function extractOmegaRuntimeMetadata(headers: Headers): OmegaRuntimeMetadata {
33	  return {
34	    omegaStack: headers.get('X-Omega-Stack') || undefined,
35	    omegaOutcome: headers.get('X-Omega-Outcome') || undefined,
36	    omegaMode: headers.get('X-Omega-Mode') || undefined,
37	    omegaCorpusClass: headers.get('X-Omega-Corpus-Class') || undefined,
38	    omegaEnvelopeVersion: headers.get('X-Omega-Envelope-Version') || undefined,
39	    omegaPhylacteryHead: headers.get('X-Omega-Phylactery-Head') || undefined,
40	    omegaRiskScore: headers.get('X-Omega-Risk-Score') || undefined,
41	    provider: headers.get('X-Provider') || undefined,
42	    providerAttempts: headers.get('X-Provider-Attempts') || undefined,
43	    sessionId: headers.get('X-Session-Id') || undefined,
44	    memoryBackend: headers.get('X-Memory-Backend') || undefined,
45	  };
46	}
47	
48	export async function chat(req: ChatRequest): Promise<ChatResponse> {
49	  const res = await fetch('/api/chat', {
50	    method: 'POST',
51	    headers: { 'Content-Type': 'application/json' },
52	    body: JSON.stringify(req),
53	  });
54	
55	  if (!res.ok) {
56	    const body = await res.json().catch(() => ({ error: res.statusText }));
57	    throw new Error((body as { error?: string }).error ?? `${res.status}`);
58	  }
59	
60	  return res.json() as Promise<ChatResponse>;
61	}
62	
63	export async function chatStream(
64	  req: ChatRequest, 
65	  onChunk: (text: string) => void,
66	  onStatus?: (text: string) => void
67	): Promise<OmegaRuntimeMetadata> {
68	  const res = await fetch('/api/chat', {
69	    method: 'POST',
70	    headers: { 'Content-Type': 'application/json' },
71	    body: JSON.stringify(req),
72	  });
73	
74	  if (!res.ok) {
75	    const body = await res.json().catch(() => ({ error: res.statusText }));
76	    throw new Error((body as { error?: string }).error ?? `${res.status}`);
77	  }
78	
79	  const metadata = extractOmegaRuntimeMetadata(res.headers);
80	
81	  if (!res.body) throw new Error("No response body");
82	
83	  const reader = res.body.getReader();
84	  const decoder = new TextDecoder();
85	  let buffer = "";
86	
87	  while (true) {
88	    const { value, done } = await reader.read();
89	    if (done) break;
90	    const chunkText = decoder.decode(value, { stream: true });
91	    buffer += chunkText;
92	
93	    // Split by SSE double newline if it looks like status events are active
94	    while (buffer.includes('\n\n')) {
95	      const idx = buffer.indexOf('\n\n');
96	      const line = buffer.slice(0, idx).trim();
97	      if (line.startsWith('data: {"type":"status"')) {
98	        try {
99	          const json = JSON.parse(line.slice(5));
100	          if (onStatus) onStatus(json.text);
101	          buffer = buffer.slice(idx + 2);
102	          continue;
103	        } catch {
104	          // fallback if parse fails
105	        }
106	      }
107	      break; // stop if front of buffer isn't a status event
108	    }
109	
110	    if (buffer && !buffer.startsWith('data: {"type":"status"')) {
111	      onChunk(buffer);
112	      buffer = "";
