'use client';

import { useEffect, useRef, useState, useCallback, type FormEvent } from 'react';
import Link from 'next/link';
import s from './page.module.css';
import { getSpeechRecognitionConstructor, type SpeechRecognitionInstance } from '@/lib/speechRecognition';
import { chatStream, type OmegaRuntimeMetadata } from '@/lib/api';

type VoiceState = 'dormant' | 'listening' | 'processing' | 'speaking';

type Message = {
  role: 'user' | 'omega';
  text: string;
};

/* ────────────────────────────────────────────
   Particle field (reduced count for performance)
   ──────────────────────────────────────────── */
function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return () => undefined;

  const resize = () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  };
  resize();
  window.addEventListener('resize', resize);

  const particles = Array.from({ length: 200 }, () => {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * 40 + 4;
    return {
      x: Math.cos(angle) * dist,
      y: Math.sin(angle) * dist,
      z: (Math.random() - 0.5) * 35,
      vx: (Math.random() - 0.5) * 0.012,
      vy: (Math.random() - 0.5) * 0.012,
      vz: (Math.random() - 0.5) * 0.01,
      radius: Math.random() * 0.9 + 0.3,
      isCyan: Math.random() > 0.5,
    };
  });

  type RGB = [number, number, number];
  const magenta: Record<VoiceState, RGB> = { dormant: [140, 0, 200], listening: [200, 0, 130], processing: [90, 0, 230], speaking: [140, 0, 200] };
  const cyan: Record<VoiceState, RGB> = { dormant: [0, 150, 185], listening: [0, 185, 215], processing: [0, 210, 240], speaking: [0, 140, 175] };

  let rotation = 0;
  let raf = 0;

  const draw = () => {
    const state = getState();
    const speed = state === 'processing' ? 1.4 : state === 'speaking' ? 1.0 : state === 'listening' ? 0.9 : 0.5;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    rotation += 0.0008 * speed;

    const cx = canvas.width / 2;
    const cy = canvas.height * 0.32;

    for (const p of particles) {
      p.x += p.vx * speed;
      p.y += p.vy * speed;
      p.z += p.vz * speed;
      if (Math.abs(p.x) > 45) p.vx *= -1;
      if (Math.abs(p.y) > 45) p.vy *= -1;
      if (Math.abs(p.z) > 22) p.vz *= -1;
    }

    const proj = particles.map((p) => {
      const rx = p.x * Math.cos(rotation) - p.z * Math.sin(rotation);
      const rz = p.x * Math.sin(rotation) + p.z * Math.cos(rotation);
      const depth = 180 / (rz + 80);
      const [r, g, b] = (p.isCyan ? cyan : magenta)[state];
      return { x: cx + rx * depth, y: cy + p.y * depth, alpha: Math.max(0.03, Math.min(0.4, depth * 0.09)), radius: p.radius * depth, r, g, b };
    });

    for (let i = 0; i < proj.length; i += 1) {
      const a = proj[i];
      for (let j = i + 1; j < proj.length; j += 4) {
        const b = proj[j];
        const dx = a.x - b.x;
        const dy = a.y - b.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 80) {
          ctx.beginPath();
          ctx.moveTo(a.x, a.y);
          ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = `rgba(${(a.r + b.r) >> 1},${(a.g + b.g) >> 1},${(a.b + b.b) >> 1},${0.035 * (1 - dist / 80)})`;
          ctx.lineWidth = 0.35;
          ctx.stroke();
        }
      }
    }

    for (const p of proj) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha})`;
      ctx.fill();
    }

    raf = requestAnimationFrame(draw);
  };

  draw();
  return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize); };
}

/* ────────────────────────────────────────────
   Audio playback — mp3 or wav
   ──────────────────────────────────────────── */
function playAudio(base64: string, mimeType: string) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return new Audio(URL.createObjectURL(new Blob([bytes], { type: mimeType || 'audio/mpeg' })));
}

/* ────────────────────────────────────────────
   Tranquility — Neural Presence Shell
   ──────────────────────────────────────────── */
export default function Tranquility() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const recognitionRef = useRef<SpeechRecognitionInstance | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const stateRef = useRef<VoiceState>('dormant');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
  const [messages, setMessages] = useState<Message[]>([]);
  const [streamingText, setStreamingText] = useState('');
  const [textInput, setTextInput] = useState('');
  const [runtimeMeta, setRuntimeMeta] = useState<OmegaRuntimeMetadata | null>(null);
  const [showRuntime, setShowRuntime] = useState(false);

  const setState = useCallback((next: VoiceState) => {
    stateRef.current = next;
    setVoiceState(next);
  }, []);

  useEffect(() => {
    if (!canvasRef.current) return undefined;
    return initParticles(canvasRef.current, () => stateRef.current);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, streamingText]);

  /* ── TTS (fire-and-forget, non-blocking) ── */
  const speakResponse = useCallback(async (text: string) => {
    try {
      const response = await fetch('/api/tts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: text.slice(0, 2000) }),
      });
      const data = await response.json();
      if (data.audio) {
        audioRef.current?.pause();
        const audio = playAudio(data.audio, data.mimeType ?? 'audio/mpeg');
        audioRef.current = audio;
        audio.onended = () => {
          if (stateRef.current === 'speaking') setState('dormant');
        };
        setState('speaking');
        await audio.play();
      }
    } catch {
      // Voice is optional — text is always shown.
    }
  }, [setState]);

  /* ── Core chat handler ── */
  const sendMessage = useCallback(async (text: string) => {
    if (!text.trim()) return;

    setMessages((prev) => [...prev, { role: 'user', text }]);
    setState('processing');
    setStreamingText('');

    try {
      let reply = '';
      const metadata = await chatStream(
        { user: text, voiceMode: true },
        (chunk) => {
          reply += chunk;
          setStreamingText(reply);
        },
      );
      setRuntimeMeta(metadata);

      const cleanReply = reply.replace(/\[VISUAL_READY\]/g, '').trim() || 'The signal falls quiet.';
      setStreamingText('');
      setMessages((prev) => [...prev, { role: 'omega', text: cleanReply }]);
      setState('dormant');

      void speakResponse(cleanReply);
    } catch {
      const fallback = 'The signal dissolves into the void.';
      setStreamingText('');
      setMessages((prev) => [...prev, { role: 'omega', text: fallback }]);
      setState('dormant');
    }
  }, [setState, speakResponse]);

  /* ── Text submit ── */
  const handleSubmit = useCallback((e: FormEvent) => {
    e.preventDefault();
    const trimmed = textInput.trim();
    if (!trimmed || voiceState === 'processing') return;
    setTextInput('');
    void sendMessage(trimmed);
  }, [textInput, voiceState, sendMessage]);

  /* ── Voice input ── */
  const toggleListening = useCallback(() => {
    if (voiceState === 'listening') {
      recognitionRef.current?.stop();
      setState('dormant');
      return;
    }

    if (voiceState !== 'dormant') return;

    const Recognition = getSpeechRecognitionConstructor();
    if (!Recognition) return;

    const recognition = new Recognition();
    recognition.continuous = false;
    recognition.interimResults = true;
    recognition.lang = 'en-US';
    recognitionRef.current = recognition;

    recognition.onstart = () => setState('listening');

    recognition.onresult = (event) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; i += 1) {
        transcript += event.results[i][0].transcript;
      }
      setTextInput(transcript.trim());
      if (event.results[event.results.length - 1]?.isFinal) {
        recognition.stop();
        const final = transcript.trim();
        if (final) {
          setTextInput('');
          void sendMessage(final);
        }
      }
    };

    recognition.onerror = () => setState('dormant');
    recognition.onend = () => { if (stateRef.current === 'listening') setState('dormant'); };

    recognition.start();
  }, [voiceState, setState, sendMessage]);

  /* ── Stop audio ── */
  const stopAudio = useCallback(() => {
    audioRef.current?.pause();
    audioRef.current = null;
    if (stateRef.current === 'speaking') setState('dormant');
  }, [setState]);

  const stateClass = s[`state${voiceState.charAt(0).toUpperCase()}${voiceState.slice(1)}`] ?? '';

  return (
    <div className={`${s.root} ${stateClass}`}>
      <canvas ref={canvasRef} className={s.canvas} />

      <Link href="/dashboard" className={s.backLink}>Dashboard</Link>

      {/* Runtime badge — top right, toggleable */}
      {runtimeMeta && (
        <button type="button" className={s.runtimeBadge} onClick={() => setShowRuntime(!showRuntime)}>
          <span className={s.runtimeDot} />
          {runtimeMeta.omegaStack ?? 'sovereign'}
        </button>
      )}

      {showRuntime && runtimeMeta && (
        <div className={s.runtimeDropdown}>
          <div className={s.rdRow}><span>Stack</span><span>{runtimeMeta.omegaStack ?? '—'}</span></div>
          <div className={s.rdRow}><span>Mode</span><span>{runtimeMeta.omegaMode ?? '—'}</span></div>
          <div className={s.rdRow}><span>Provider</span><span>{runtimeMeta.provider ?? '—'}</span></div>
          <div className={s.rdRow}><span>Outcome</span><span>{runtimeMeta.omegaOutcome ?? '—'}</span></div>
          <div className={s.rdRow}><span>Memory</span><span>{runtimeMeta.memoryBackend ?? '—'}</span></div>
          <div className={s.rdRow}><span>Risk</span><span>{runtimeMeta.omegaRiskScore ?? '—'}</span></div>
          <div className={s.rdRow}><span>Envelope</span><span>{runtimeMeta.omegaEnvelopeVersion ?? '—'}</span></div>
          <div className={s.rdRow}><span>Phylactery</span><span className={s.mono}>{runtimeMeta.omegaPhylacteryHead ?? '—'}</span></div>
        </div>
      )}

      <div className={s.main}>
        {/* Omega header */}
        <div className={s.header}>
          <button type="button" className={s.omegaWrapper} onClick={toggleListening} aria-label="Toggle voice input">
            <div className={s.omegaGlow} />
            <div className={s.innerRing} />
            <div className={s.omegaSymbol}>&Omega;</div>
          </button>
          <div className={s.status}>
            {voiceState === 'listening' ? 'Listening...' : voiceState === 'processing' ? 'Thinking...' : voiceState === 'speaking' ? 'Speaking...' : 'OmegA'}
          </div>
        </div>

        {/* Chat messages */}
        <div className={s.chatArea}>
          {messages.length === 0 && !streamingText && (
            <div className={s.emptyState}>Ask OmegA anything. Type below or tap the symbol to speak.</div>
          )}

          {messages.map((msg, i) => (
            <div key={i} className={`${s.msg} ${msg.role === 'user' ? s.msgUser : s.msgOmega}`}>
              {msg.role === 'omega' && <span className={s.msgLabel}>&Omega;</span>}
              <div className={s.msgText}>{msg.text}</div>
            </div>
          ))}

          {streamingText && (
            <div className={`${s.msg} ${s.msgOmega}`}>
              <span className={s.msgLabel}>&Omega;</span>
              <div className={s.msgText}>{streamingText}<span className={s.cursor} /></div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input bar — always visible */}
        <div className={s.inputBar}>
          {voiceState === 'speaking' && (
            <button type="button" className={s.stopBtn} onClick={stopAudio} aria-label="Stop audio">
              Stop
            </button>
          )}
          <form className={s.inputForm} onSubmit={handleSubmit}>
            <button
              type="button"
              className={`${s.micBtn} ${voiceState === 'listening' ? s.micBtnActive : ''}`}
              onClick={toggleListening}
              disabled={voiceState === 'processing'}
              aria-label="Voice input"
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z" />
                <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
                <line x1="12" x2="12" y1="19" y2="22" />
              </svg>
            </button>
            <input
              type="text"
              className={s.textInput}
              placeholder={voiceState === 'listening' ? 'Listening...' : 'Message OmegA...'}
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              disabled={voiceState === 'processing'}
            />
            <button type="submit" className={s.sendBtn} disabled={!textInput.trim() || voiceState === 'processing'}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="22" x2="11" y1="2" y2="13" />
                <polygon points="22 2 15 22 11 13 2 9 22 2" />
              </svg>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

