API_BASE = os.environ.get("OMEGA_API_URL", "https://omega-sovereign-megas-projects-1fcf4ba6.vercel.app")
HISTORY_FILE = Path.home() / ".omega" / "cli" / "history.txt"

C = sys.stdout.isatty()
def cyan(t):   return f"\033[36;1m{t}\033[0m" if C else t
def magenta(t):return f"\033[35;1m{t}\033[0m" if C else t
def dim(t):    return f"\033[2m{t}\033[0m" if C else t
def bold(t):   return f"\033[1m{t}\033[0m" if C else t
def red(t):    return f"\033[31m{t}\033[0m" if C else t

# ── Env loading ───────────────────────────────────────────────────────────────

def load_env():
    for path in ENV_FILES:
        if not path.exists():
            continue
        for line in path.read_text().splitlines():
            line = line.strip()
            if not line or line.startswith("#") or "=" not in line:
                continue
            k, v = line.split("=", 1)
            os.environ.setdefault(k.strip(), v.strip().strip('"').strip("'"))

# ── Streaming chat ────────────────────────────────────────────────────────────

def chat_stream(user: str, history: list) -> str:
    token = os.environ.get("OMEGA_OPERATOR_TOKEN", "").strip()
    if not token:
        print(red("warning: OMEGA_OPERATOR_TOKEN not set — running in public mode"), file=sys.stderr)

    payload = json.dumps({
        "user": user,
        "history": history,
        "voiceMode": False,
    }).encode()

    headers = {
        "Content-Type": "application/json",
        "x-omega-operator-token": token,
    }

    req = urllib.request.Request(
        f"{API_BASE}/api/chat",
        data=payload,
        headers=headers,
        method="POST",
    )

    full = ""
    mode = "?"
    try:
        with urllib.request.urlopen(req, timeout=120) as resp:
            mode = resp.headers.get("X-Omega-Mode", "?")
            print(magenta("Ω "), end="", flush=True)
            buf = b""
            while True:
                chunk = resp.read(256)
                if not chunk:
                    break
                buf += chunk
                # flush complete lines to avoid partial JSON status lines
                while b"\n" in buf:
                    line, buf = buf.split(b"\n", 1)
                    text = line.decode("utf-8", errors="replace")
                    if text.startswith('data: {"type":"status"'):
                        continue  # skip status events
                    if text.strip():
                        print(text, end="", flush=True)
                        full += text
            # flush remainder
            if buf:
                text = buf.decode("utf-8", errors="replace")
                if not text.startswith('data: {"type":"status"'):
                    print(text, end="", flush=True)
                    full += text
            print()  # newline after response
    except urllib.error.HTTPError as e:
        body = e.read().decode("utf-8", errors="replace")
        print(red(f"\nerror {e.code}: {body}"), file=sys.stderr)
    except urllib.error.URLError as e:
        print(red(f"\nconnection error: {e.reason}"), file=sys.stderr)

    return full, mode

# ── REPL ──────────────────────────────────────────────────────────────────────

def setup_readline():
    try:
        import readline
        HISTORY_FILE.parent.mkdir(parents=True, exist_ok=True)
        if HISTORY_FILE.exists():
            readline.read_history_file(str(HISTORY_FILE))
        import atexit
        atexit.register(lambda: readline.write_history_file(str(HISTORY_FILE)))
    except ImportError:
        pass

def banner(mode: str = "operator"):
    print(magenta("  Ω  OmegA"))
    print(dim(f"  mode: {mode}  ·  /new to clear history  ·  /exit to quit"))
    print()

def repl():
    setup_readline()
    history = []
    last_mode = "operator"
    banner(last_mode)

    while True:
        try:
            line = input(magenta("you › ")).strip()
        except (EOFError, KeyboardInterrupt):
            print()
            return

        if not line:
            continue
        if line in ("/exit", "/quit", "exit", "quit"):
            return
        if line == "/new":
            history.clear()
            print(dim("  session cleared"))
            continue
        if line == "/help":
            print(dim("  /new    clear conversation history"))
            print(dim("  /exit   quit"))
            continue

        reply, mode = chat_stream(line, history)
        last_mode = mode
        if reply:
            history.append({"role": "user", "text": line})
            history.append({"role": "omega", "text": reply})
        print()

def one_shot(prompt: str):
    reply, _ = chat_stream(prompt, [])
    return 0 if reply else 1

# ── Entry ─────────────────────────────────────────────────────────────────────

def main():
    load_env()

    args = sys.argv[1:]

    if not args:
        if not sys.stdin.isatty():
            prompt = sys.stdin.read().strip()
            if prompt:
                return one_shot(prompt)
        repl()
        return 0

    if args[0] in ("help", "-h", "--help"):
        print("Usage: omega                  interactive REPL")
        print("       omega \"question\"        one-shot query")
        print("       omega /new              clear and restart")
        return 0

    return one_shot(" ".join(args))

if __name__ == "__main__":
    try:
        sys.exit(main())
    except KeyboardInterrupt:
        print()
        sys.exit(0)

