#!/usr/bin/env python3
import json
import os
import subprocess
import sys
import time
import uuid
from pathlib import Path
from threading import Event, Thread
from urllib import error, request


API_URL = os.environ.get("OMEGA_API_URL", "http://127.0.0.1:8787")
USER_ID = os.environ.get("OMEGA_USER_ID", "sovereign")
STATE_DIR = Path.home() / ".omega" / "cli"
STATE_FILE = STATE_DIR / "state.json"
HISTORY_FILE = STATE_DIR / "history.txt"
ENV_FILES = [
    Path.home() / ".omega" / "gateway.env",
    Path.home() / ".omega" / "one-true.env",
]
KNOWN_MODES = {
    "auto",
    "omega",
    "local",
    "cloud",
    "anthropic",
    "claude",
    "google",
    "",
    "perplexity",
    "deepseek",
    "xai",
    "grok",
    "codex_cli",
    "codex_cli_rw",
}

SPINNER_FRAMES = ["|", "/", "-", "\\"]
COLOR = sys.stdout.isatty() and os.environ.get("TERM") not in {"dumb", None}
REPO_CANDIDATES = [
    Path(os.environ.get("OMEGA_REPO", "")).expanduser() if os.environ.get("OMEGA_REPO") else None,
    Path("/home/mega/OMEGA_WORKSPACE/CANON/OmegA-Architecture"),
    Path("/home/mega/OmegA-Architecture"),
]


def style(text: str, code: str) -> str:
    if not COLOR:
        return text
    return f"\033[{code}m{text}\033[0m"


def load_env() -> None:
    for path in ENV_FILES:
        if not path.exists():
            continue
        for raw_line in path.read_text(encoding="utf-8").splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#") or "=" not in line:
                continue
            key, value = line.split("=", 1)
            value = value.strip().strip('"').strip("'")
            os.environ.setdefault(key, value)


def ensure_state_dir() -> None:
    STATE_DIR.mkdir(parents=True, exist_ok=True)


def load_state() -> dict:
    ensure_state_dir()
    if not STATE_FILE.exists():
        return {}
    try:
        return json.loads(STATE_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def save_state(state: dict) -> None:
    ensure_state_dir()
    STATE_FILE.write_text(json.dumps(state, indent=2), encoding="utf-8")


def get_session_state() -> dict:
    state = load_state()
    if not state.get("session_id"):
        state["session_id"] = str(uuid.uuid4())
    if not state.get("mode"):
        state["mode"] = "auto"
    return state


def reset_session() -> dict:
    state = load_state()
    state["session_id"] = str(uuid.uuid4())
    save_state(state)
    return state


def configure_history() -> None:
    try:
        import readline  # type: ignore
    except Exception:
        return

    ensure_state_dir()
    try:
        if HISTORY_FILE.exists():
            readline.read_history_file(str(HISTORY_FILE))
    except Exception:
        pass

    def _save_history() -> None:
        try:
            readline.write_history_file(str(HISTORY_FILE))
        except Exception:
            pass

    import atexit

    atexit.register(_save_history)


def headers() -> dict:
    hdrs = {"Content-Type": "application/json"}
    token = os.environ.get("OMEGA_API_BEARER_TOKEN", "").strip()
    if token:
        hdrs["Authorization"] = f"Bearer {token}"
    return hdrs


def spinner(label: str, stop: Event) -> None:
    start = time.time()
    idx = 0
    while not stop.is_set():
        frame = SPINNER_FRAMES[idx % len(SPINNER_FRAMES)]
        elapsed = time.time() - start
        text = f"\r{style(frame, '35;1')} {label} {style(f'({elapsed:0.1f}s)', '2')}"
        print(text, end="", file=sys.stderr, flush=True)
        time.sleep(0.12)
        idx += 1
    print("\r" + " " * 60 + "\r", end="", file=sys.stderr, flush=True)


def api_post(path: str, payload: dict, timeout: int = 180) -> dict:
    data = json.dumps(payload).encode("utf-8")
    req = request.Request(
        f"{API_URL.rstrip('/')}{path}",
        data=data,
        headers=headers(),
        method="POST",
    )
    try:
        with request.urlopen(req, timeout=timeout) as resp:
            body = resp.read().decode("utf-8")
            return json.loads(body) if body else {}
    except error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="replace")
        raise RuntimeError(f"gateway error {exc.code}: {body}") from exc
    except error.URLError as exc:
        raise RuntimeError(f"gateway unavailable: {exc.reason}") from exc


def api_get(path: str, timeout: int = 10) -> str:
    req = request.Request(
        f"{API_URL.rstrip('/')}{path}",
        headers=headers(),
        method="GET",
    )
    try:
        with request.urlopen(req, timeout=timeout) as resp:
            return resp.read().decode("utf-8")
    except error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="replace")
        raise RuntimeError(f"gateway error {exc.code}: {body}") from exc
    except error.URLError as exc:
        raise RuntimeError(f"gateway unavailable: {exc.reason}") from exc


def api_get_json(path: str, timeout: int = 10) -> dict:
    body = api_get(path, timeout=timeout)
    return json.loads(body) if body else {}


def resolve_repo_path() -> Path | None:
    for candidate in REPO_CANDIDATES:
        if candidate and candidate.exists():
            return candidate
    return None


def run_voice(args: list[str]) -> int:
    repo = resolve_repo_path()
    if repo is None:
        print("omega voice: repo path not found. Set OMEGA_REPO to the OmegA-Architecture root.", file=sys.stderr)
        return 1
    start_script = repo / "voice" / "start.sh"
    install_script = repo / "voice" / "install.sh"
    venv_python = repo / "voice" / ".venv" / "bin" / "python"
    if not start_script.exists():
        print(f"omega voice: missing {start_script}", file=sys.stderr)
        return 1
    if install_script.exists() and (os.environ.get("OMEGA_VOICE_FORCE_INSTALL") == "1" or not venv_python.exists()):
        try:
            print(style("[omega voice] ensuring voice dependencies...", "36;1"))
            result = subprocess.run(
                ["bash", str(install_script)],
                check=False,
                stdout=sys.stdout,
                stderr=sys.stderr,
            )
            if result.returncode != 0:
                print("[omega voice] install failed; aborting.", file=sys.stderr)
                return result.returncode
        except Exception as exc:
            print(f"[omega voice] install failed: {exc}", file=sys.stderr)
            return 1
    cmd = ["bash", str(start_script)] + args
    return subprocess.call(cmd)


def chat(prompt: str, mode: str, session_id: str) -> dict:
    # Keep the gateway task state minimal. Heavy wrapper-side scaffolding was
    # biasing the router toward the legacy "no record" path even when memory
    # hits were available.
    payload_task_state = {
        "task_id": str(uuid.uuid4()),
        "objective": "answer",
        "constraints": [],
        "success_criteria": [],
        "declared_unknowns": [],
        "urgency": "normal",
        "intent_priority_score": 0.0,
        "authority_shrink_level": 0.0,
        "canon_anchor_weight": 0.0,
        "predicted_failure_modes": [],
    }

    payload = {
        "user": prompt,
        "mode": mode,
        "sessionId": session_id,
        "userId": USER_ID,
        "allowWrite": False,
        "use_memory": True,
        "temperature": 0.2,
        "task_state": payload_task_state,
    }
    return api_post("/api/v1/chat", payload)


def codex_exec(prompt: str, mode: str) -> dict:
    sandbox = "workspace-write" if mode == "codex_cli_rw" else "read-only"
    cmd = [
        "codex",
        "-a",
        "never",
        "exec",
        "--skip-git-repo-check",
        "--sandbox",
        sandbox,
        "--color",
        "never",
        "--json",
        prompt,
    ]
    proc = subprocess.run(
        cmd,
        capture_output=True,
        text=True,
        timeout=180,
        check=False,
    )
    if proc.returncode != 0:
        stderr = (proc.stderr or proc.stdout).strip()
        raise RuntimeError(f"codex direct route failed: {stderr}")

    reply = None
    for line in proc.stdout.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            event = json.loads(line)
        except json.JSONDecodeError:
            continue
        item = event.get("item") or {}
        if event.get("type") == "item.completed" and item.get("type") == "agent_message":
            reply = item.get("text")
    if not reply:
        raise RuntimeError("codex direct route returned no reply")
    return {"mode": mode, "reply": reply, "provider": "codex-direct"}


def infer_mode(prompt: str, configured_mode: str) -> str:
    if configured_mode != "auto":
        return configured_mode

    text = prompt.lower()

    if any(term in text for term in ["anthropic", "claude", "opus", "sonnet"]):
        return "claude"
    if any(term in text for term in ["", "google flash", "google pro"]):
        return ""
    if any(term in text for term in ["perplexity", "latest web", "web search", "search the web", "look it up"]):
        return "perplexity"
    if any(term in text for term in ["deepseek"]):
        return "deepseek"
    if any(term in text for term in ["grok", "xai"]):
        return "grok"
    if any(term in text for term in ["offline", "local only", "ollama", "on this machine only"]):
        return "local"
    if any(term in text for term in ["write code", "edit code", "patch", "implement", "refactor", "fix the code", "change the code"]):
        return "codex_cli_rw"
    if any(term in text for term in ["review this code", "audit this code", "inspect the code", "debug the code", "analyze the repo", "review the repo"]):
        return "codex_cli"
    if any(term in text for term in ["fast", "cheap", "fallback", "use whatever works"]):
        return "omega"

    return "omega"


def chat_with_feedback(prompt: str, configured_mode: str, session_id: str) -> dict:
    chosen_mode = infer_mode(prompt, configured_mode)
    if chosen_mode in {"codex_cli", "codex_cli_rw"}:
        return codex_exec(prompt, chosen_mode)
    stop = Event()
    worker = None
    if sys.stderr.isatty():
        label = f"OmegA is reasoning via {chosen_mode}"
        worker = Thread(target=spinner, args=(label, stop), daemon=True)
        worker.start()
    try:
        data = chat(prompt, chosen_mode, session_id)
    finally:
        stop.set()
        if worker is not None:
            worker.join(timeout=0.5)

    if not data.get("mode"):
        data["mode"] = chosen_mode
    return data


def print_reply(data: dict) -> None:
    reply = data.get("reply") or data.get("message") or data.get("output")
    mode = data.get("mode")
    if mode:
        print(style(f"[mode: {mode}]", "36;1"))
    if reply:
        print(reply)
        return
    print(json.dumps(data, indent=2))


def print_trace(limit: int = 5) -> None:
    data = api_get_json("/api/v1/trace")
    events = data.get("events") or []
    if not events:
        print("no trace events")
        return
    for ev in events[:limit]:
        print(style(f"[{ev.get('phase_state') or ev.get('phase')}] {ev.get('action')}", "36;1"))
        print(
            " ".join(
                [
                    f"outcome={ev.get('outcome')}",
                    f"amp={ev.get('resonance_amplitude')}",
                    f"shear={ev.get('shear_index')}",
                    f"canon={ev.get('canon_anchor_weight')}",
                    f"priority={ev.get('intent_priority_score')}",
                    f"shrink={ev.get('authority_shrink_level')}",
                ]
            )
        )
        predicted = ev.get("predicted_failure_modes")
        if predicted:
            print(f"predicted={','.join(predicted)}")
        actual = ev.get("actual_failure_mode")
        if actual:
            print(f"actual={actual}")
        print(style(str(ev.get("timestamp", "")), "2"))
        print()


def usage() -> None:
    print(
        "OmegA conversational CLI\n\n"
        "Usage:\n"
        "  omega                    Start a normal conversation\n"
        "  omega \"<prompt>\"         Send a one-shot prompt\n"
        "  omega health             Check the live gateway\n"
        "  omega trace              Show recent trace signals\n"
        "  omega voice              Start voice-to-voice session\n"
        "  omega help               Show help\n\n"
        "Interactive controls:\n"
        "  /help                    Show conversation controls\n"
        "  /new                     Start a fresh session\n"
        "  /mode <name>             Change routing mode (or /mode auto)\n"
        "  /health                  Check gateway health\n"
        "  /trace                   Show recent trace signals\n"
        "  /exit                    Quit\n"
    )


def print_banner(state: dict) -> None:
    print(style("OmegA", "35;1"))
    print(style("Talk normally. OmegA decides how to handle the task.", "2"))
    print(style(f"session: {state['session_id'][:8]}  mode: {state['mode']}", "36"))
    print(style("Use /mode auto to keep routing automatic.", "2"))


def repl() -> int:
    configure_history()
    state = get_session_state()
    save_state(state)
    print_banner(state)
    while True:
        try:
            line = input(style("omega> ", "35;1")).strip()
        except EOFError:
            print()
            return 0
        except KeyboardInterrupt:
            print()
            return 0

        if not line:
            continue
        if line in {"/exit", "/quit"}:
            return 0
        if line == "/help":
            usage()
            continue
        if line == "/new":
            state = reset_session()
            if not state.get("mode"):
                state["mode"] = "auto"
            save_state(state)
            print(style(f"new session: {state['session_id'][:8]}", "32;1"))
            continue
        if line == "/health":
            print(api_get("/health"))
            continue
        if line == "/trace":
            print_trace()
            continue
        if line == "/voice":
            return run_voice([])
        if line.startswith("/mode "):
            next_mode = line.split(None, 1)[1].strip()
            if next_mode not in KNOWN_MODES:
                print(f"unknown mode: {next_mode}")
                print("known modes:", ", ".join(sorted(KNOWN_MODES)))
                continue
            state["mode"] = next_mode
            save_state(state)
            print(style(f"mode: {next_mode}", "32;1"))
            continue

        try:
            response = chat_with_feedback(line, state["mode"], state["session_id"])
            print_reply(response)
        except Exception as exc:
            print(f"error: {exc}", file=sys.stderr)


def one_shot(prompt: str) -> int:
    state = reset_session()
    save_state(state)
    response = chat(prompt, "omega", state["session_id"])
    print_reply(response)
    return 0


def main(argv: list[str]) -> int:
    load_env()

    if len(argv) == 1:
        if not sys.stdin.isatty():
            piped = sys.stdin.read().strip()
            if piped:
                return one_shot(piped)
        return repl()

    cmd = argv[1]
    if cmd in {"help", "-h", "--help"}:
        usage()
        return 0
    if cmd in {"health", "status"}:
        print(api_get("/health"))
        return 0
    if cmd == "trace":
        print_trace()
        return 0
    if cmd in {"voice", "v2v"}:
        return run_voice(argv[2:])
    if cmd in {"ask", "run"}:
        if len(argv) < 3:
            print("prompt required", file=sys.stderr)
            return 2
        return one_shot(" ".join(argv[2:]))

    # Default behavior: treat all args as a natural-language prompt.
    return one_shot(" ".join(argv[1:]))


if __name__ == "__main__":
    try:
        raise SystemExit(main(sys.argv))
    except Exception as exc:
        print(f"error: {exc}", file=sys.stderr)
        raise SystemExit(1)

