@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500&family=Instrument+Serif:ital@0;1&display=swap');

.root {
  position: fixed;
  inset: 0;
  background: #010104;
  color: white;
  overflow: hidden;
  font-family: 'Space Grotesk', system-ui, sans-serif;
}

.canvas {
  position: fixed;
  inset: 0;
  z-index: 0;
  opacity: 0.7;
}

.backLink {
  position: fixed;
  top: 1rem;
  left: 1.2rem;
  z-index: 30;
  font-size: 0.62rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.2);
  text-decoration: none;
  transition: color 0.2s;
}
.backLink:hover { color: rgba(255, 255, 255, 0.55); }

/* ── Runtime badge (top-right) ── */
.runtimeBadge {
  position: fixed;
  top: 1rem;
  right: 1.2rem;
  z-index: 30;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.35rem 0.7rem;
  border: 1px solid rgba(0, 229, 255, 0.12);
  border-radius: 999px;
  background: rgba(2, 2, 8, 0.7);
  color: rgba(0, 229, 255, 0.5);
  font-size: 0.56rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  cursor: pointer;
  backdrop-filter: blur(12px);
  transition: border-color 0.2s, color 0.2s;
}
.runtimeBadge:hover { border-color: rgba(0, 229, 255, 0.3); color: rgba(0, 229, 255, 0.7); }

.runtimeDot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: rgba(0, 229, 255, 0.6);
  animation: pulse 2s ease-in-out infinite;
}

.runtimeDropdown {
  position: fixed;
  top: 3.2rem;
  right: 1.2rem;
  z-index: 30;
  width: 260px;
  padding: 0.8rem;
  background: rgba(2, 2, 8, 0.92);
  border: 1px solid rgba(0, 229, 255, 0.1);
  border-radius: 12px;
  backdrop-filter: blur(20px);
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
}

.rdRow {
  display: flex;
  justify-content: space-between;
  font-size: 0.62rem;
  color: rgba(255, 255, 255, 0.5);
}
.rdRow span:first-child {
  color: rgba(255, 255, 255, 0.28);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}
.mono {
  font-family: 'Space Grotesk', monospace;
  font-size: 0.56rem;
  max-width: 140px;
  overflow: hidden;
  text-overflow: ellipsis;
  color: rgba(0, 229, 255, 0.45);
}

/* ── Main layout ── */
.main {
  position: relative;
