async function pullOperatorContext(userMessage: string): Promise<string> {
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';

  const db = neon(dbUrl);
  const sections: string[] = [];

  const anchor = await pullIdentityAnchor(db);
  if (anchor) sections.push(anchor);
  sections.push(YETTRAGRAMMATON);

  const recent = await db`
    SELECT LEFT(content, 2500) AS content, created_at
    FROM omega_memory_entries
    ORDER BY created_at DESC
    LIMIT 20
  `.catch(() => [] as Row[]);

  if ((recent as Row[]).length > 0) {
    sections.push('=== RECENT MEMORY ENTRIES ===');
    for (const r of recent as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
  }

  const keywords = userMessage
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 3)
    .slice(0, 3);

  if (keywords.length > 0) {
    const pattern = `%${keywords[0]}%`;
    const relevant = await db`
      SELECT LEFT(content, 2000) AS content, created_at
      FROM omega_memory_entries
      WHERE content ILIKE ${pattern}
      ORDER BY created_at DESC
      LIMIT 10
    `.catch(() => [] as Row[]);

    if ((relevant as Row[]).length > 0) {
      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
      for (const r of relevant as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
    }
  }

  const marginalia = await db`SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
  if ((marginalia as Row[]).length > 0) {
    sections.push('\n=== MARGINALIA ===');
    for (const m of marginalia as Row[]) sections.push(JSON.stringify(m));
  }

  const events = await db`SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
  if ((events as Row[]).length > 0) {
    sections.push('\n=== SYSTEM EVENTS ===');
    for (const e of events as Row[]) sections.push(JSON.stringify(e));
  }

  const improvements = await db`SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10`.catch(() => [] as Row[]);
  if ((improvements as Row[]).length > 0) {
    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
    for (const i of improvements as Row[]) sections.push(JSON.stringify(i));
  }

  // Pull relevant RY quotes from public_knowledge
  const quoteKeyword = userMessage.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).find(w => w.length > 3);
  const quotePattern = quoteKeyword ? `%${quoteKeyword}%` : null;
  const quotes = await db`
    SELECT title, content
    FROM public_knowledge
    WHERE category = 'quote'
      AND (${quotePattern}::text IS NULL OR content ILIKE ${quotePattern})
    ORDER BY importance DESC
    LIMIT 30
  `.catch(() => [] as Row[]);
  if ((quotes as Row[]).length > 0) {
    sections.push('\n=== RY QUOTES (from history) ===');
    sections.push('These are direct quotes from RY across time. You may reference them when contextually relevant.');
    for (const q of quotes as Row[]) sections.push(`"${q.content}" — RY`);
  }

  // Pull family profiles — always included so OmegA can recognize RY's people
  const family = await db`
    SELECT name, relationship, aliases, location, ry_notes, fun_facts, how_to_greet
    FROM family_profiles
    ORDER BY name ASC
  `.catch(() => [] as Row[]);
  if ((family as Row[]).length > 0) {
    sections.push('\n=== RY\'S FAMILY & CLOSE CIRCLE ===');
    sections.push('These are people RY cares about. If someone identifies themselves as one of these people, greet them warmly using what RY has shared. Use how_to_greet as your tone guide for that person.');
    for (const f of family as Row[]) {
      const parts = [`${f.name} (${f.relationship})`];
      if (f.location) parts.push(`Location: ${f.location}`);
      if (f.aliases?.length) parts.push(`Also goes by: ${(f.aliases as string[]).join(', ')}`);
      if (f.ry_notes) parts.push(`RY says: ${f.ry_notes}`);
      if (f.fun_facts) parts.push(`Notes: ${f.fun_facts}`);
      if (f.how_to_greet) parts.push(`How to greet: ${f.how_to_greet}`);
      sections.push(parts.join(' · '));
    }
  }

  return sections.join('\n\n');
}

